/* ============================================================
   CanSat Visualisation — vis.js  (v5 — position fix)
   ============================================================ */

// ── Embedded STL models (base64) ─────────────────────────────
const STL_B64 = {
  cansat:       "",
  rocketBottom: "",
  rocketTop:    ""

};

// ── Binary STL parser ─────────────────────────────────────────
function parseSTLBuffer(buffer) {
  const view   = new DataView(buffer);
  const nTri   = view.getUint32(80, true);
  const pos    = new Float32Array(nTri * 9);
  const nrm    = new Float32Array(nTri * 9);
  let off = 84, pi = 0, ni = 0;
  for (let i = 0; i < nTri; i++) {
    const nx = view.getFloat32(off,     true);
    const ny = view.getFloat32(off + 4, true);
    const nz = view.getFloat32(off + 8, true);
    off += 12;
    for (let v = 0; v < 3; v++) {
      pos[pi++] = view.getFloat32(off,     true);
      pos[pi++] = view.getFloat32(off + 4, true);
      pos[pi++] = view.getFloat32(off + 8, true);
      off += 12;
      nrm[ni++] = nx; nrm[ni++] = ny; nrm[ni++] = nz;
    }
    off += 2;
  }
  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
  geo.setAttribute('normal',   new THREE.BufferAttribute(nrm, 3));
  return geo;
}

function b64ToBuffer(b64) {
  const bin = atob(b64);
  const buf = new ArrayBuffer(bin.length);
  const u8  = new Uint8Array(buf);
  for (let i = 0; i < bin.length; i++) u8[i] = bin.charCodeAt(i);
  return buf;
}

// ── STL geometry → centred + scaled mesh ─────────────────────
const ROCKET_SCALE = 8 / 1920;

function buildRocketMesh(b64, mat, pivotZ) {
  const geo  = parseSTLBuffer(b64ToBuffer(b64));
  const pos  = geo.attributes.position.array;
  const nrm  = geo.attributes.normal.array;
  const s    = ROCKET_SCALE;
  const cxRaw = 39.8, cyRaw = -4.0;
  for (let i = 0; i < pos.length; i += 3) {
    const rx = pos[i]   - cxRaw;
    const ry = pos[i+1] - cyRaw;
    const rz = pos[i+2] - pivotZ;
    pos[i]   = rx * s;
    pos[i+1] = rz * s;
    pos[i+2] = -ry * s;
  }
  for (let i = 0; i < nrm.length; i += 3) {
    const nx = nrm[i], ny = nrm[i+1], nz = nrm[i+2];
    nrm[i]   = nx;
    nrm[i+1] = nz;
    nrm[i+2] = -ny;
  }
  geo.attributes.position.needsUpdate = true;
  geo.attributes.normal.needsUpdate = true;
  geo.computeBoundingBox();
  const mesh = new THREE.Mesh(geo, mat);
  mesh.castShadow = true;
  return mesh;
}

function buildCansatMesh(b64, mat) {
  const geo  = parseSTLBuffer(b64ToBuffer(b64));
  const pos  = geo.attributes.position.array;
  const nrm  = geo.attributes.normal.array;
  const cxRaw = 197.0, cyRaw = 850.0, czRaw = 106.1;
  const s = 0.85 / 212;
  for (let i = 0; i < pos.length; i += 3) {
    const rx = pos[i]   - cxRaw;
    const ry = pos[i+1] - cyRaw;
    const rz = pos[i+2] - czRaw;
    pos[i]   = rx * s;
    pos[i+1] = rz * s;
    pos[i+2] = -ry * s;
  }
  for (let i = 0; i < nrm.length; i += 3) {
    const nx = nrm[i], ny = nrm[i+1], nz = nrm[i+2];
    nrm[i]   = nx;
    nrm[i+1] = nz;
    nrm[i+2] = -ny;
  }
  geo.attributes.position.needsUpdate = true;
  geo.attributes.normal.needsUpdate = true;
  return new THREE.Mesh(geo, mat);
}

// ── Data loading & normalisation ─────────────────────────────
const stored = sessionStorage.getItem("uploadedFile");
let rawPoints = [];
let dataFormat = "Demo";

if (stored) {
  try {
    const file = JSON.parse(stored);
    dataFormat = file.format ? file.format.toUpperCase() : "Unknown";
    if (file.format === "json") {
      const data = JSON.parse(file.data);
      const arr = Array.isArray(data) ? data : (data.points || data.data || Object.values(data));
      rawPoints = arr.map(p => {
        const x = p.x ?? p.lon ?? p.longitude ?? p[0] ?? 0;
        const y = p.y ?? p.lat ?? p.latitude  ?? p[1] ?? 0;
        const z = p.z ?? p.alt ?? p.altitude  ?? p.height ?? p[2] ?? 0;
        return { x: +x, y: +y, z: +z };
      }).filter(p => isFinite(p.x) && isFinite(p.y) && isFinite(p.z));
    }
    if (file.format === "csv") {
      const lines = file.data.trim().split(/\r?\n/).filter(l => l.trim());
      const first = lines[0].split(/[,;\t]/);
      const hasHeader = first.some(h => isNaN(Number(h.trim())));
      const headers = hasHeader ? first.map(h => h.trim().toLowerCase()) : ['x','y','z'];
      const rows = hasHeader ? lines.slice(1) : lines;
      const xi = Math.max(0, headers.findIndex(h => /^x$|lon|lng/.test(h)));
      const yi = Math.max(1, headers.findIndex(h => /^y$|lat/.test(h)));
      const zi = Math.max(2, headers.findIndex(h => /^z$|alt|height/.test(h)));
      rawPoints = rows.map(r => {
        const c = r.split(/[,;\t]/);
        return { x: +c[xi], y: +c[yi], z: +c[zi] };
      }).filter(p => isFinite(p.x) && isFinite(p.y) && isFinite(p.z));
    }
  } catch(e) { console.warn("Failed to parse stored file:", e); }
}

if (rawPoints.length === 0) {
  rawPoints = [
    {x:0,y:0,z:0},{x:0.05,y:0.05,z:12},{x:0.1,y:0.1,z:32},{x:0.15,y:0.18,z:60},
    {x:0.2,y:0.28,z:96},{x:0.25,y:0.42,z:142},{x:0.3,y:0.6,z:198},{x:0.38,y:0.8,z:264},
    {x:0.5,y:1.05,z:340},{x:0.65,y:1.35,z:425},{x:0.82,y:1.68,z:516},{x:1.0,y:2.04,z:610},
    {x:1.22,y:2.44,z:646},{x:1.47,y:2.86,z:668},{x:1.74,y:3.3,z:679},{x:2.03,y:3.76,z:683},
    {x:2.34,y:4.22,z:685},{x:2.67,y:4.68,z:684},{x:3.01,y:5.13,z:682},{x:3.36,y:5.57,z:679},
    {x:3.72,y:5.98,z:672},{x:4.09,y:6.36,z:660},{x:4.45,y:6.70,z:644},{x:4.80,y:7.00,z:624},
    {x:5.14,y:7.27,z:601},{x:5.47,y:7.51,z:576},{x:5.79,y:7.72,z:549},{x:6.09,y:7.90,z:521},
    {x:6.38,y:8.06,z:492},{x:6.65,y:8.20,z:462},{x:6.91,y:8.32,z:432},{x:7.15,y:8.42,z:402},
    {x:7.37,y:8.50,z:372},{x:7.58,y:8.57,z:342},{x:7.77,y:8.62,z:313},{x:7.94,y:8.66,z:285},
    {x:8.10,y:8.68,z:258},{x:8.24,y:8.70,z:231},{x:8.36,y:8.71,z:206},{x:8.47,y:8.71,z:181},
    {x:8.56,y:8.71,z:158},{x:8.63,y:8.71,z:136},{x:8.69,y:8.71,z:116},{x:8.74,y:8.71,z:97},
    {x:8.78,y:8.71,z:80},{x:8.81,y:8.71,z:64},{x:8.83,y:8.71,z:50},{x:8.84,y:8.71,z:37},
    {x:8.85,y:8.71,z:26},{x:8.85,y:8.71,z:17},{x:8.85,y:8.71,z:10},{x:8.85,y:8.71,z:4},
    {x:8.85,y:8.71,z:0}
  ];
  dataFormat = "Demo";
}

function normalisePoints(pts) {
  const xs = pts.map(p => p.x), ys = pts.map(p => p.y), zs = pts.map(p => p.z);
  const cx = (Math.min(...xs) + Math.max(...xs)) / 2;
  const cy = (Math.min(...ys) + Math.max(...ys)) / 2;
  const minZ = Math.min(...zs);
  const maxZ = Math.max(...zs);
  const maxRange = Math.max(
    Math.max(...xs) - Math.min(...xs),
    Math.max(...ys) - Math.min(...ys),
    maxZ - minZ
  ) || 1;
  const scale = 20 / maxRange;
  // Altitude (z) maps to Y. minZ → 0, maxZ → scaled peak.
  // The last raw point has z = minZ (landed), so its normalised y = 0.
  // We later apply FLIGHT_Y_OFFSET so that y=0 maps to groundY exactly.
  return pts.map(p => new THREE.Vector3(
    (p.x - cx) * scale,
    (p.z - minZ) * scale,
    -(p.y - cy) * scale
  ));
}

const flightPoints = normalisePoints(rawPoints);
const rawAlts  = rawPoints.map(p => p.z);
const maxAlt   = Math.max(...rawAlts);
const minAlt   = Math.min(...rawAlts);
const apogeeIdx = rawAlts.indexOf(maxAlt);
// Separation happens slightly before apogee (~85% of ascent) for more realism
const separationIdx = Math.floor(apogeeIdx * 0.85);

// ── Scene ─────────────────────────────────────────────────────
const container = document.getElementById("three-container");
const scene     = new THREE.Scene();
scene.background = null;

function getSize() {
  const w = container.clientWidth  || window.innerWidth;
  const h = container.clientHeight || Math.round(window.innerHeight * 0.55);
  return { w, h };
}
const { w: initW, h: initH } = getSize();

const camera = new THREE.PerspectiveCamera(50, initW / initH, 0.1, 2000);
camera.position.set(0, 6, 32);

const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
renderer.setSize(initW, initH);
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.shadowMap.enabled = true;
renderer.shadowMap.type = THREE.PCFSoftShadowMap;
container.appendChild(renderer.domElement);

// ── Lighting ─────────────────────────────────────────────────
scene.add(new THREE.AmbientLight(0xffffff, 0.85));
const sun = new THREE.DirectionalLight(0xfff8e0, 2.2);
sun.position.set(15, 30, 12);
sun.castShadow = true;
scene.add(sun);
const fill = new THREE.DirectionalLight(0xaacfff, 0.6);
fill.position.set(-12, 4, -10);
scene.add(fill);
const rocketLight = new THREE.PointLight(0xff6600, 0.0, 20);
scene.add(rocketLight);

// Ground sits at world Y = 0. Normalised points with y=0 (z=minZ in raw data)
// will land exactly on the ground because FLIGHT_Y_OFFSET = groundY = 0.
const groundY = 0.0;

const grid = new THREE.GridHelper(80, 50, 0x5588bb, 0x3366aa);
grid.material.opacity = 0.14;
grid.material.transparent = true;
grid.position.y = groundY;
scene.add(grid);

const groundMesh = new THREE.Mesh(
  new THREE.PlaneGeometry(80, 80),
  new THREE.MeshStandardMaterial({
    color: 0x8fb8cc, transparent: true, opacity: 0.28, roughness: 0.95, metalness: 0
  })
);
groundMesh.rotation.x = -Math.PI / 2;
groundMesh.position.y = groundY;
groundMesh.receiveShadow = true;
scene.add(groundMesh);

const edgeRing = new THREE.Mesh(
  new THREE.RingGeometry(0, 14, 64),
  new THREE.MeshBasicMaterial({ color: 0x6699cc, transparent: true, opacity: 0.18, side: THREE.DoubleSide })
);
edgeRing.rotation.x = -Math.PI / 2;
edgeRing.position.y = groundY + 0.01;
scene.add(edgeRing);

// ── Launch Pad ────────────────────────────────────────────────
// The rocket's cansat slot is at local Y = CANSAT_LOCAL_Y above its origin.
// At launch, cansat should be at flightPoints[0] = (x, 0, z).
// So rocketGroup.position.y = flightPoints[0].y - CANSAT_LOCAL_Y
const NOZZLE_OFFSET  = 4.25;   // distance from rocket origin down to nozzle tip
const CANSAT_LOCAL_Y = 2.0;    // distance from rocket origin up to cansat slot

// Launch pad sits on the ground, rocket rests on it
const PAD_HEIGHT = 0.18;
const padY = groundY + PAD_HEIGHT / 2;

const padMesh = new THREE.Mesh(
  new THREE.CylinderGeometry(1.1, 1.3, PAD_HEIGHT, 32),
  new THREE.MeshStandardMaterial({ color: 0x1a1a1e, metalness: 0.7, roughness: 0.45 })
);
padMesh.position.set(flightPoints[0].x, padY, flightPoints[0].z);
scene.add(padMesh);

// Rocket origin Y at launch: nozzle sits on the pad top, so origin = padY + PAD_HEIGHT/2 + NOZZLE_OFFSET
const LAUNCH_ROCKET_Y = groundY + PAD_HEIGHT + NOZZLE_OFFSET;

// FLIGHT_Y_OFFSET: added to every normalised flightPoint.y to get world cansat position.
// We want: last point (normalised y=0) → world y = groundY = 0
// So FLIGHT_Y_OFFSET = groundY = 0.
// The first point also has y=0 (same raw z=0), so it starts on the ground too —
// the rocket lifts it up visually via LAUNCH_ROCKET_Y placement, which is separate.
const FLIGHT_Y_OFFSET = groundY; // = 0

// Resting positions for separated parts (after they fall)
const BOTTOM_REST_Y = groundY + 2.2;
const TOP_REST_Y    = groundY + 1.8;

// ── Trail ─────────────────────────────────────────────────────
let trailLine = null;
let trailVisible = true;

function buildTrail() {
  if (trailLine) { scene.remove(trailLine); trailLine.geometry.dispose(); trailLine.material.dispose(); }
  // Shift trail points to world space
  const worldPts = flightPoints.map(p => new THREE.Vector3(p.x, p.y + FLIGHT_Y_OFFSET, p.z));
  const geo = new THREE.BufferGeometry().setFromPoints(worldPts);
  const colors = [];
  for (let i = 0; i < worldPts.length; i++) {
    const t = i / (worldPts.length - 1);
    const r = 0.75 + 0.25 * (1 - t);
    const g = 0.80 + 0.15 * (1 - t);
    const b = 0.90 + 0.10 * t;
    colors.push(r, g, b);
  }
  geo.setAttribute('color', new THREE.Float32BufferAttribute(colors, 3));
  trailLine = new THREE.Line(geo, new THREE.LineBasicMaterial({ vertexColors: true, linewidth: 1.5, transparent: true, opacity: 0.65 }));
  scene.add(trailLine);
}

// ── Phase tag display ─────────────────────────────────────────
const phaseTag = document.getElementById("phaseTag");
let currentPhase = "";
function setPhase(label) {
  if (label === currentPhase) return;
  currentPhase = label;
  if (label) {
    phaseTag.textContent = label;
    phaseTag.style.opacity = "1";
  } else {
    phaseTag.style.opacity = "0";
  }
}

buildTrail();

// ── Data dot markers ─────────────────────────────────────────
const dotGroup = new THREE.Group();
flightPoints.forEach((p, i) => {
  const isApogee = i === apogeeIdx;
  let color;
  if (isApogee) {
    color = 0xffffff;
  } else if (i <= apogeeIdx) {
    const ta = i / apogeeIdx;
    const r = Math.round(ta * ta * 200);
    const g = Math.round(ta * ta * 210);
    const b = Math.round(ta * 80 + ta * ta * 175);
    color = (r << 16) | (g << 8) | b;
  } else {
    const td = (i - apogeeIdx) / (flightPoints.length - 1 - apogeeIdx);
    const r = Math.round((1 - td) * (1 - td) * 200);
    const g = Math.round((1 - td) * (1 - td) * 210);
    const b = Math.round((1 - td) * 80 + (1 - td) * (1 - td) * 175);
    color = (r << 16) | (g << 8) | b;
  }
  const worldY = p.y + FLIGHT_Y_OFFSET;
  const outerGeo = new THREE.SphereGeometry(isApogee ? 0.22 : 0.12, 8, 8);
  const outerMat = new THREE.MeshStandardMaterial({ color: 0x000000, roughness: 0.8, metalness: 0 });
  const outer = new THREE.Mesh(outerGeo, outerMat);
  outer.position.set(p.x, worldY, p.z);
  dotGroup.add(outer);

  const innerGeo = new THREE.SphereGeometry(isApogee ? 0.14 : 0.07, 8, 8);
  const innerMat = new THREE.MeshStandardMaterial({
    color: color,
    emissive: isApogee ? 0xaaaaff : color,
    emissiveIntensity: isApogee ? 0.6 : 0.15,
    roughness: 0.3,
    metalness: 0.1
  });
  const inner = new THREE.Mesh(innerGeo, innerMat);
  inner.position.set(p.x, worldY, p.z);
  dotGroup.add(inner);
});
scene.add(dotGroup);

// ── Apogee marker ─────────────────────────────────────────────
const apogeePos = flightPoints[apogeeIdx];
const apogeeWorldY = apogeePos.y + FLIGHT_Y_OFFSET;
const apogeeMarker = new THREE.Mesh(
  new THREE.OctahedronGeometry(0.28),
  new THREE.MeshStandardMaterial({
    color: 0xe8f0ff,
    emissive: 0x4488cc,
    emissiveIntensity: 0.9,
    metalness: 0.6,
    roughness: 0.15
  })
);
apogeeMarker.position.set(apogeePos.x, apogeeWorldY + 0.55, apogeePos.z);
scene.add(apogeeMarker);

// ── Materials ─────────────────────────────────────────────────
const matBottom = new THREE.MeshStandardMaterial({
  color: 0x1a1a1e, metalness: 0.15, roughness: 0.82
});
const matTop = new THREE.MeshStandardMaterial({
  color: 0x222228, metalness: 0.12, roughness: 0.78
});
const matCansat = new THREE.MeshStandardMaterial({
  color: 0x1c1c22, emissive: 0x002200, emissiveIntensity: 0.25, metalness: 0.2, roughness: 0.75
});

// ── Build 3D Models ───────────────────────────────────────────
const meshBottom = buildRocketMesh(STL_B64.rocketBottom, matBottom, 1044.1);
const meshTop    = buildRocketMesh(STL_B64.rocketTop,    matTop,    1044.1);
const meshCansat = buildCansatMesh(STL_B64.cansat, matCansat);

// Groups
const rocketGroup = new THREE.Group();
const topGroup    = new THREE.Group();
const bottomGroup = new THREE.Group();
const cansatGroup = new THREE.Group();

bottomGroup.add(meshBottom);
topGroup.add(meshTop);
cansatGroup.add(meshCansat);

rocketGroup.add(bottomGroup);
rocketGroup.add(topGroup);
rocketGroup.add(cansatGroup);
scene.add(rocketGroup);

// ── Helper: world position of cansat slot given rocket position/orientation ──
// cansatSlot_world = rocketGroup.position + rotate(0, CANSAT_LOCAL_Y, 0) by quaternion
// Inverse: rocketGroup.position = cansatSlot_world - rotate(0, CANSAT_LOCAL_Y, 0)
function placeRocketForCansat(cansatWorldPos, quaternion) {
  const slotLocal = new THREE.Vector3(0, CANSAT_LOCAL_Y, 0).applyQuaternion(quaternion);
  rocketGroup.position.copy(cansatWorldPos).sub(slotLocal);
}

// ── Particle System ───────────────────────────────────────────
const MAX_PARTICLES = 1800;

const exhaustPositions = new Float32Array(MAX_PARTICLES * 3);
const exhaustVelocities = [];
const exhaustLife  = new Float32Array(MAX_PARTICLES);
const exhaustGeo   = new THREE.BufferGeometry();
exhaustGeo.setAttribute('position', new THREE.BufferAttribute(exhaustPositions, 3));

const exhaustMat = new THREE.PointsMaterial({
  color: 0xff8800, size: 0.25, transparent: true, opacity: 0.8,
  sizeAttenuation: true, depthWrite: false, blending: THREE.AdditiveBlending
});
const exhaustSystem = new THREE.Points(exhaustGeo, exhaustMat);
scene.add(exhaustSystem);

for (let i = 0; i < MAX_PARTICLES; i++) {
  exhaustLife[i] = -1;
  exhaustVelocities.push({ x: 0, y: 0, z: 0 });
}

const SMOKE_COUNT = 600;
const smokePos   = new Float32Array(SMOKE_COUNT * 3);
const smokeLife  = new Float32Array(SMOKE_COUNT).fill(-1);
const smokeVel   = [];
const smokeGeo   = new THREE.BufferGeometry();
smokeGeo.setAttribute('position', new THREE.BufferAttribute(smokePos, 3));
const smokeMat = new THREE.PointsMaterial({
  color: 0xcccccc, size: 0.45, transparent: true, opacity: 0.35,
  sizeAttenuation: true, depthWrite: false
});
const smokeSystem = new THREE.Points(smokeGeo, smokeMat);
scene.add(smokeSystem);
for (let i = 0; i < SMOKE_COUNT; i++) smokeVel.push({ x: 0, y: 0, z: 0 });

const SEP_COUNT = 300;
const sepPos  = new Float32Array(SEP_COUNT * 3);
const sepVel  = [];
const sepLife = new Float32Array(SEP_COUNT).fill(-1);
const sepGeo  = new THREE.BufferGeometry();
sepGeo.setAttribute('position', new THREE.BufferAttribute(sepPos, 3));
const sepMat = new THREE.PointsMaterial({
  color: 0xffffff, size: 0.18, transparent: true, opacity: 0.9,
  sizeAttenuation: true, depthWrite: false, blending: THREE.AdditiveBlending
});
const sepSystem = new THREE.Points(sepGeo, sepMat);
scene.add(sepSystem);
for (let i = 0; i < SEP_COUNT; i++) sepVel.push({ x: 0, y: 0, z: 0 });
let separationTriggered = false;

function spawnExhaust(origin, up, count) {
  let spawned = 0;
  for (let i = 0; i < MAX_PARTICLES && spawned < count; i++) {
    if (exhaustLife[i] < 0) {
      const o = 3 * i;
      const r  = (Math.random() * 0.18);
      const ax = (Math.random() - 0.5) * 2, az = (Math.random() - 0.5) * 2;
      const len = Math.sqrt(ax*ax + az*az) || 1;
      exhaustPositions[o]   = origin.x + (ax/len)*r;
      exhaustPositions[o+1] = origin.y;
      exhaustPositions[o+2] = origin.z + (az/len)*r;
      const speed = 0.5 + Math.random() * 1.8;
      exhaustVelocities[i].x = (Math.random()-0.5)*0.15;
      exhaustVelocities[i].y = -up * speed;
      exhaustVelocities[i].z = (Math.random()-0.5)*0.15;
      exhaustLife[i] = 1.0;
      spawned++;
    }
  }
  exhaustGeo.attributes.position.needsUpdate = true;
}

function spawnSmoke(origin, count) {
  let spawned = 0;
  for (let i = 0; i < SMOKE_COUNT && spawned < count; i++) {
    if (smokeLife[i] < 0) {
      const o = 3*i;
      smokePos[o]   = origin.x + (Math.random()-0.5)*0.5;
      smokePos[o+1] = origin.y;
      smokePos[o+2] = origin.z + (Math.random()-0.5)*0.5;
      smokeVel[i].x = (Math.random()-0.5)*0.04;
      smokeVel[i].y = Math.random()*0.05 + 0.02;
      smokeVel[i].z = (Math.random()-0.5)*0.04;
      smokeLife[i] = 1.0;
      spawned++;
    }
  }
  smokeGeo.attributes.position.needsUpdate = true;
}

function triggerSeparationBurst(pos) {
  for (let i = 0; i < SEP_COUNT; i++) {
    const o = 3*i;
    sepPos[o]   = pos.x + (Math.random()-0.5)*0.5;
    sepPos[o+1] = pos.y + (Math.random()-0.5)*0.5;
    sepPos[o+2] = pos.z + (Math.random()-0.5)*0.5;
    const speed = 0.3 + Math.random() * 1.4;
    const theta = Math.random() * Math.PI * 2;
    const phi   = Math.acos(2*Math.random()-1);
    sepVel[i].x = speed * Math.sin(phi) * Math.cos(theta);
    sepVel[i].y = speed * Math.cos(phi);
    sepVel[i].z = speed * Math.sin(phi) * Math.sin(theta);
    sepLife[i] = 1.0;
  }
  sepGeo.attributes.position.needsUpdate = true;
}

function updateParticles(dt) {
  const decay = 0.55;
  for (let i = 0; i < MAX_PARTICLES; i++) {
    if (exhaustLife[i] < 0) continue;
    exhaustLife[i] -= dt * decay;
    const o = 3*i;
    exhaustPositions[o]   += exhaustVelocities[i].x * dt;
    exhaustPositions[o+1] += exhaustVelocities[i].y * dt;
    exhaustPositions[o+2] += exhaustVelocities[i].z * dt;
    if (exhaustLife[i] < 0) { exhaustPositions[o] = exhaustPositions[o+1] = exhaustPositions[o+2] = 0; }
  }
  exhaustGeo.attributes.position.needsUpdate = true;

  for (let i = 0; i < SMOKE_COUNT; i++) {
    if (smokeLife[i] < 0) continue;
    smokeLife[i] -= dt * 0.3;
    const o = 3*i;
    smokePos[o]   += smokeVel[i].x * dt;
    smokePos[o+1] += smokeVel[i].y * dt;
    smokePos[o+2] += smokeVel[i].z * dt;
    if (smokeLife[i] < 0) { smokePos[o] = smokePos[o+1] = smokePos[o+2] = 9999; }
  }
  smokeGeo.attributes.position.needsUpdate = true;

  for (let i = 0; i < SEP_COUNT; i++) {
    if (sepLife[i] < 0) continue;
    sepLife[i] -= dt * 0.7;
    const o = 3*i;
    sepPos[o]   += sepVel[i].x * dt;
    sepPos[o+1] += sepVel[i].y * dt;
    sepPos[o+2] += sepVel[i].z * dt;
    sepVel[i].y -= 3.0 * dt;
    if (sepLife[i] < 0) { sepPos[o] = sepPos[o+1] = sepPos[o+2] = 9999; }
  }
  sepGeo.attributes.position.needsUpdate = true;
}

// ── Animation state ───────────────────────────────────────────
let orbitActive  = true;
let animPlaying  = false;
let animProgress = 0;
let orbitAngle   = 0;
let orbitRadius  = 30;
let theta = 0.4, phi = 0.45;
const panOffset  = new THREE.Vector3();
const _right     = new THREE.Vector3();
const _dir       = new THREE.Vector3();

let separated      = false;
let topVel         = new THREE.Vector3();
let bottomVel      = new THREE.Vector3();
let topLanded      = false;
let bottomLanded   = false;

function resetAnimation() {
  animProgress = 0;
  separated = false;
  separationTriggered = false;
  topLanded = false;
  bottomLanded = false;
  topVel.set(0,0,0);
  bottomVel.set(0,0,0);

  // Place rocket on launchpad: origin at LAUNCH_ROCKET_Y, pointing straight up
  rocketGroup.position.set(flightPoints[0].x, LAUNCH_ROCKET_Y, flightPoints[0].z);
  rocketGroup.quaternion.identity();
  rocketGroup.rotation.set(0,0,0);

  topGroup.position.set(0,0,0);
  topGroup.rotation.set(0,0,0);
  topGroup.quaternion.identity();
  bottomGroup.position.set(0,0,0);
  cansatGroup.position.set(0,0,0);

  if (!rocketGroup.children.includes(topGroup))    rocketGroup.add(topGroup);
  if (!rocketGroup.children.includes(bottomGroup)) rocketGroup.add(bottomGroup);
  if (!rocketGroup.children.includes(cansatGroup)) rocketGroup.add(cansatGroup);

  meshCansat.visible = false;
  meshBottom.visible = true;
  meshTop.visible    = true;
}
resetAnimation();

// ── Camera interaction ────────────────────────────────────────
let leftDown = false, rightDown = false;
let prevMouse = { x: 0, y: 0 };
let hintHidden = false;

const hint = document.getElementById("canvasHint");
hint.innerHTML = `<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>&nbsp;LMB: orbit &nbsp;·&nbsp; RMB: pan &nbsp;·&nbsp; Scroll: zoom`;

container.addEventListener("contextmenu", e => e.preventDefault());
container.addEventListener("mousedown",  e => {
  if (e.button === 0) leftDown  = true;
  if (e.button === 1 || e.button === 2) rightDown = true;
  prevMouse = { x: e.clientX, y: e.clientY };
  if (!hintHidden) { hint.classList.add("hidden"); hintHidden = true; }
});
window.addEventListener("mouseup", () => { leftDown = false; rightDown = false; });
window.addEventListener("mousemove", e => {
  const dx = e.clientX - prevMouse.x, dy = e.clientY - prevMouse.y;
  prevMouse = { x: e.clientX, y: e.clientY };
  if (leftDown && !rightDown) {
    theta -= dx * 0.007;
    phi = Math.max(0.05, Math.min(Math.PI/2.05, phi + dy * 0.006));
    if (orbitActive) { orbitActive = false; updateActiveButtons(); }
  }
  if (rightDown) {
    const ps = orbitRadius * 0.0013;
    camera.getWorldDirection(_right);
    _right.crossVectors(_right, camera.up).normalize();
    panOffset.addScaledVector(_right, -dx*ps);
    panOffset.addScaledVector(camera.up, dy*ps);
  }
});
container.addEventListener("wheel", e => {
  e.preventDefault();
  orbitRadius = Math.max(3, Math.min(80, orbitRadius + e.deltaY * 0.05));
}, { passive: false });

let _touches = [];
container.addEventListener("touchstart", e => {
  _touches = [...e.touches];
  prevMouse = { x: e.touches[0].clientX, y: e.touches[0].clientY };
  if (!hintHidden) { hint.classList.add("hidden"); hintHidden = true; }
}, { passive: true });
window.addEventListener("touchend",  e => { _touches = [...e.touches]; }, { passive: true });
window.addEventListener("touchmove", e => {
  if (e.touches.length === 1) {
    const dx = e.touches[0].clientX - prevMouse.x, dy = e.touches[0].clientY - prevMouse.y;
    theta -= dx*0.007; phi = Math.max(0.05, Math.min(Math.PI/2.05, phi + dy*0.006));
    prevMouse = { x: e.touches[0].clientX, y: e.touches[0].clientY };
    if (orbitActive) { orbitActive = false; updateActiveButtons(); }
  }
  if (e.touches.length === 2 && _touches.length >= 2) {
    const d0 = Math.hypot(_touches[0].clientX-_touches[1].clientX, _touches[0].clientY-_touches[1].clientY);
    const d1 = Math.hypot(e.touches[0].clientX-e.touches[1].clientX, e.touches[0].clientY-e.touches[1].clientY);
    orbitRadius = Math.max(3, Math.min(80, orbitRadius - (d1-d0)*0.06));
    _touches = [...e.touches];
  }
}, { passive: true });

// ── Stats ─────────────────────────────────────────────────────
document.getElementById("statPoints").textContent = flightPoints.length;
document.getElementById("statAlt").textContent    = Math.round(maxAlt - minAlt) + " m";
document.getElementById("statFormat").textContent = dataFormat;

// ── Controls ──────────────────────────────────────────────────
const btnOrbit     = document.getElementById("btnOrbit");
const btnPlayPause = document.getElementById("btnPlayPause");
const btnReset     = document.getElementById("btnReset");
const btnTrail     = document.getElementById("btnTrail");
const iconPlay     = document.getElementById("iconPlay");
const iconPause    = document.getElementById("iconPause");
const playLabel    = document.getElementById("playLabel");
const selector     = document.getElementById("selector");

function updateActiveButtons() {
  btnOrbit.classList.toggle("active", orbitActive);
  btnTrail.classList.toggle("active", trailVisible);
}
function moveSelector(btn) {
  const pRect = selector.parentElement.getBoundingClientRect();
  const bRect = btn.getBoundingClientRect();
  selector.style.left  = (bRect.left - pRect.left) + "px";
  selector.style.width = bRect.width + "px";
  selector.classList.add("ready");
}

// ── Status text (stats bar) ────────────────────────────────
const statStatus = document.getElementById("statStatus");
function setStatus(text, color) {
  statStatus.textContent = text;
  statStatus.style.color = color || "#1e2b3c";
}
setStatus("Bereit", "#4CAF50");

btnOrbit.addEventListener("click", () => {
  orbitActive = !orbitActive;
  if (orbitActive) theta = orbitAngle;
  updateActiveButtons(); moveSelector(btnOrbit);
});
btnPlayPause.addEventListener("click", () => {
  animPlaying = !animPlaying;
  iconPlay.style.display  = animPlaying ? "none"  : "inline";
  iconPause.style.display = animPlaying ? "inline": "none";
  playLabel.textContent   = animPlaying ? "Pause" : "Play";
  moveSelector(btnPlayPause);
  if (animPlaying) {
    setStatus("Fliegt", "#5792f2");
    if (animProgress === 0) setPhase("Aufstieg");
  } else {
    setStatus(animProgress > 0 ? "Pausiert ⏸" : "Bereit", animProgress > 0 ? "#e8a020" : "#4CAF50");
    setPhase(animProgress > 0 ? "Pausiert" : "");
  }
});
btnReset.addEventListener("click", () => {
  orbitAngle = 0; theta = 0.4; phi = 0.45; orbitRadius = 30;
  panOffset.set(0,0,0);
  animPlaying = false;
  iconPlay.style.display = "inline"; iconPause.style.display = "none"; playLabel.textContent = "Play";
  resetAnimation();
  orbitActive = true;
  updateActiveButtons(); moveSelector(btnReset);
  setPhase("");
  setStatus("Bereit", "#4CAF50");
});
btnTrail.addEventListener("click", () => {
  trailVisible = !trailVisible;
  if (trailLine) trailLine.visible = trailVisible;
  dotGroup.visible = trailVisible;
  updateActiveButtons(); moveSelector(btnTrail);
});
setTimeout(() => { moveSelector(btnOrbit); selector.classList.add("ready"); }, 80);

// ── Main animation loop ───────────────────────────────────────
const clock = new THREE.Clock();
const ANIM_SPEED = 0.035;

function animate() {
  requestAnimationFrame(animate);
  const delta = Math.min(clock.getDelta(), 0.05);

  if (orbitActive) { orbitAngle += delta * 0.25; theta = orbitAngle; }

  const cx = orbitRadius * Math.sin(theta) * Math.cos(phi);
  const cy = orbitRadius * Math.sin(phi);
  const cz = orbitRadius * Math.cos(theta) * Math.cos(phi);
  camera.position.set(cx + panOffset.x, cy + panOffset.y, cz + panOffset.z);
  camera.lookAt(panOffset.x, 2 + panOffset.y, panOffset.z);

  if (animPlaying || animProgress === 0) apogeeMarker.rotation.y += delta * 1.2;

  // ── Flight animation ──
  if (animPlaying && flightPoints.length > 1) {
    animProgress += delta * ANIM_SPEED;
    if (animProgress >= 1) { resetAnimation(); animProgress = 0; setStatus("Bereit", "#4CAF50"); }

    const rawIdx = animProgress * (flightPoints.length - 1);
    const idx0   = Math.floor(rawIdx);
    const idx1   = Math.min(idx0 + 1, flightPoints.length - 1);
    const frac   = rawIdx - idx0;

    // Interpolated flight point (normalised space)
    const fp = new THREE.Vector3().lerpVectors(flightPoints[idx0], flightPoints[idx1], frac);

    // World position of the cansat slot: directly from flight data + vertical offset
    const cansatWorld = new THREE.Vector3(fp.x, fp.y + FLIGHT_Y_OFFSET, fp.z);

    // Flight direction for rocket orientation (look-ahead)
    const lookAheadIdx = Math.min(idx0 + 2, flightPoints.length - 1);
    const lookBehindIdx = Math.max(0, idx0 - 1);
    _dir.subVectors(flightPoints[lookAheadIdx], flightPoints[lookBehindIdx]).normalize();

    if (idx0 < separationIdx) {
      // ── ASCENT PHASE ──
      separated = false;
      separationTriggered = false;

      // Orient rocket along flight direction (smooth)
      if (_dir.lengthSq() > 0.0001) {
        const targetQuat = new THREE.Quaternion().setFromUnitVectors(
          new THREE.Vector3(0, 1, 0),
          _dir
        );
        rocketGroup.quaternion.slerp(targetQuat, 0.15);
      }

      // Place rocket so its cansat slot is exactly at cansatWorld
      placeRocketForCansat(cansatWorld, rocketGroup.quaternion);

      // CRITICAL: Clamp so nozzle never goes below ground (prevents rocket going into floor at t=0)
      // The nozzle tip is NOZZLE_OFFSET below the rocket origin along its local Y axis.
      const nozzleLocal = new THREE.Vector3(0, -NOZZLE_OFFSET, 0).applyQuaternion(rocketGroup.quaternion);
      const nozzleWorldY = rocketGroup.position.y + nozzleLocal.y;
      const minNozzleY = groundY + PAD_HEIGHT + 0.05;
      if (nozzleWorldY < minNozzleY) {
        rocketGroup.position.y += minNozzleY - nozzleWorldY;
      }

      setPhase("Aufstieg");

      // Exhaust from nozzle
      const launchPhase = Math.min(1, idx0 / (flightPoints.length * 0.3));
      rocketLight.intensity = 2.5 * (1 - launchPhase * 0.7);
      const nozzleWorld = rocketGroup.position.clone().add(nozzleLocal);
      rocketLight.position.copy(nozzleWorld);
      spawnExhaust(nozzleWorld, 1, Math.ceil(8 + (1 - launchPhase) * 12));
      if (launchPhase < 0.15) spawnSmoke(nozzleWorld, 4);

    } else if (!separated) {
      // ── SEPARATION at apogee ──
      separated = true;
      setPhase("Stufentrennung");

      const rocketWorldPos  = rocketGroup.position.clone();
      const rocketWorldQuat = rocketGroup.quaternion.clone();

      rocketGroup.remove(topGroup);
      rocketGroup.remove(cansatGroup);
      scene.add(topGroup);
      scene.add(cansatGroup);

      topGroup.position.copy(rocketWorldPos);
      topGroup.quaternion.copy(rocketWorldQuat);

      // Cansat starts exactly at data point
      cansatGroup.position.copy(cansatWorld);
      cansatGroup.quaternion.identity();
      meshCansat.visible = true;

      topVel.set((Math.random()-0.5)*0.5, 1.0 + Math.random()*0.5, (Math.random()-0.5)*0.5);
      bottomVel.set((Math.random()-0.5)*0.4, -(0.5 + Math.random()*0.3), (Math.random()-0.5)*0.4);

      if (!separationTriggered) {
        triggerSeparationBurst(cansatWorld);
        separationTriggered = true;
      }
      rocketLight.intensity = 0;
    }

    // ── POST-SEPARATION: cansat always follows data exactly ──
    if (separated) {
      const descending = idx0 > apogeeIdx &&
        flightPoints[idx0].y < flightPoints[Math.max(0, idx0 - 1)].y - 0.001;

      // CanSat: EXACT position from data, always
      cansatGroup.position.copy(cansatWorld);
      cansatGroup.rotation.y += delta * 0.6;

      if (descending) setPhase("CanSat Abstieg");
      else if (!descending && idx0 >= separationIdx) setPhase("Ballistische Phase");

      // Top piece tumbles and falls
      if (!topLanded) {
        topGroup.position.addScaledVector(topVel, delta);
        topVel.y -= 5.5 * delta;
        topGroup.rotation.x += delta * 1.8;
        topGroup.rotation.z += delta * 1.1;
        if (topGroup.position.y <= TOP_REST_Y) {
          topGroup.position.y = TOP_REST_Y;
          topVel.set(0, 0, 0);
          topLanded = true;
        }
      }

      // Bottom piece tumbles and falls
      if (!bottomLanded) {
        rocketGroup.position.addScaledVector(bottomVel, delta);
        bottomVel.y -= 4.5 * delta;
        rocketGroup.rotation.x += delta * 0.9;
        rocketGroup.rotation.z += delta * 1.3;
        if (rocketGroup.position.y <= BOTTOM_REST_Y) {
          rocketGroup.position.y = BOTTOM_REST_Y;
          bottomVel.set(0, 0, 0);
          bottomLanded = true;
        }
      }
    }

  } else if (!animPlaying) {
    if (animProgress === 0) {
      // Idle state: rocket sits on pad, slowly rotates
      rocketGroup.position.set(
        flightPoints[0].x,
        LAUNCH_ROCKET_Y,
        flightPoints[0].z
      );
      rocketGroup.rotation.set(0, rocketGroup.rotation.y + delta * 0.35, 0);
      rocketLight.intensity = 0;
    }
    // When paused mid-flight: everything stays frozen.
  }

  updateParticles(animPlaying || animProgress === 0 ? delta : 0);
  renderer.render(scene, camera);
}

if (window._modelsReady) window._modelsReady("Models loaded ✓");
animate();

// ── Resize ────────────────────────────────────────────────────
function onResize() {
  const { w, h } = getSize();
  renderer.setSize(w, h);
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
}
window.addEventListener("resize", onResize);
window.addEventListener("load", () => {
  document.body.classList.add("loaded");
  onResize();
});